/* default box: width = content only */
.card { box-sizing: border-box; }
/* now width INCLUDES padding + border */

/* flex: distribute along ONE axis */
.nav { display: flex; gap: 1rem; }

/* grid: control BOTH axes */
.layout { display: grid; grid-template-columns: 200px 1fr; }

:root { font-size: 16px; }
h1 { font-size: 2rem; }   /* 32px, but scales */
.box { padding: 1rem; }  /* respects user prefs */

:root { --bg: white; --fg: black; }
[data-theme="dark"] { --bg: black; --fg: white; }
body { background: var(--bg); color: var(--fg); }

/* janky: triggers layout each frame */
.bad { transition: width 0.3s; }

/* smooth: GPU-friendly */
.good { transition: transform 0.3s; }
